BEGIN;

UPDATE public.programs
SET
  title = '21-Day Deep Sleep Reset',
  total_days = 21,
  has_audio = true,
  content_mode = 'template',
  time_slots_enabled = true,
  updated_at = NOW()
WHERE slug = 'sleep_disorder_reset';

ON CONFLICT (program_slug) DO UPDATE
SET template_slots = EXCLUDED.template_slots,
    updated_at = NOW();


ON CONFLICT (program_slug, day_number) DO UPDATE
SET day_title = EXCLUDED.day_title,
    phase = EXCLUDED.phase,
    day_goal = EXCLUDED.day_goal,
    variables = EXCLUDED.variables,
    overrides = EXCLUDED.overrides,
    updated_at = NOW();

COMMIT;
