INSERT INTO public.program_templates (program_slug, template_slots)
VALUES
  ('sleep_disorder_reset', '[{"slot_id":"intro","card_type":"intro","timeSlot":"anytime","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"dayNumber":"{day_number}","dayTitle":"{day_title}","goal":"{day_goal}","estimatedMinutes":"{estimated_minutes}"}},{"slot_id":"lesson","card_type":"lesson","timeSlot":"anytime","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"title":"Today''s Focus","paragraphs":["{day_goal}"],"highlight":"{lesson_highlight}"}},{"slot_id":"morning_sunlight","card_type":"action_step","timeSlot":"morning","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":"{sunlight_instructions}","whyThisWorks":"{sunlight_why}"}},{"slot_id":"hydration_breathing","card_type":"breathing_exercise","timeSlot":"morning","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"title":"Hydration + Nervous System Activation","instructions":"{breathing_instructions}","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10}},{"slot_id":"morning_movement","card_type":"exercise_routine","timeSlot":"morning","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"title":"{movement_title}","exercises":"{movement_exercises}"}},{"slot_id":"caffeine_rule","card_type":"action_step","timeSlot":"anytime","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"stepNumber":2,"title":"Caffeine Control Rule","instructions":"{caffeine_instructions}","whyThisWorks":"{caffeine_why}"}},{"slot_id":"evening_downshift","card_type":"mindfulness_exercise","timeSlot":"evening","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"title":"Evening Nervous System Downshift","steps":"{downshift_steps}","completionMessage":"Stay with the practice until your body and mind feel steadier."}},{"slot_id":"sleep_audio","card_type":"audio","timeSlot":"evening","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"title":"Tonight''s Guided Sleep Audio","description":"Press play during your evening wind-down or once you are in bed.","audioStoragePath":"{audio_day_path}","durationSeconds":"{audio_duration_seconds}"}},{"slot_id":"temperature_trick","card_type":"mindfulness_exercise","timeSlot":"evening","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"title":"Body Temperature Sleep Trick","steps":"{temperature_steps}","completionMessage":"Stay with the practice until your body and mind feel steadier."}},{"slot_id":"military_sleep_method","card_type":"mindfulness_exercise","timeSlot":"evening","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"title":"The Military Sleep Method (fast Sleep Technique)","steps":"{military_steps}","completionMessage":"Stay with the practice until your body and mind feel steadier."}},{"slot_id":"daily_sleep_trick","card_type":"mindfulness_exercise","timeSlot":"evening","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"title":"{trick_title}","steps":"{trick_steps}","completionMessage":"Stay with the practice until your body and mind feel steadier."}},{"slot_id":"evening_journal","card_type":"journal","timeSlot":"evening","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"prompt":"What helped you most on Day {day_number}?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"}},{"slot_id":"close","card_type":"close","timeSlot":"evening","isTimeSensitive":false,"hasEffortCheck":false,"card_template":{"message":"Day {day_number} is complete.","secondaryMessage":"{close_secondary_message}"}}]'::jsonb)
INSERT INTO public.program_progressions (program_slug, day_number, day_title, phase, day_goal, variables, overrides)
VALUES
  ('sleep_disorder_reset', 1, 'Reset the Body Clock', 'Phase 1: Reset the Clock', 'Start resetting the body clock and nervous system so the brain begins recognizing the signals for sleep. Tonight’s sleep may not be perfect yet, but the body has already begun the reset process.', '{"day_number":1,"day_title":"Reset the Body Clock","day_goal":"Start resetting the body clock and nervous system so the brain begins recognizing the signals for sleep. Tonight’s sleep may not be perfect yet, but the body has already begun the reset process.","estimated_minutes":13,"lesson_highlight":"Stay consistent and let the routine do the work.","sunlight_instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","If sunlight is weak, increase exposure to 20–30 minutes."],"sunlight_why":"Morning sunlight resets the brain’s circadian clock, which tells your body when to release melatonin at night. Without this signal, the brain stays confused about when to sleep.","breathing_instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This reduces stress hormones, which are one of the biggest causes of insomnia.","movement_title":"Morning Movement (sleep Pressure Builder)","movement_exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]}],"caffeine_instructions":["Today follow this rule strictly:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Caffeine stays in the body 6–8 hours, often silently disturbing sleep."],"caffeine_why":"Small consistent actions reinforce stability and support restful sleep.","downshift_steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Let the body relax naturally.","Recommended length: 10–20 minutes."],"audio_day_path":"sleep_disorder_reset/day-01.mp3","audio_duration_seconds":610,"temperature_steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, your body temperature drops, which triggers natural sleepiness.","This trick is commonly used in sleep clinics."],"military_steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a canoe on a calm lake.","The sky above you is clear and peaceful.","The water is still and quiet.","Focus on the scene while breathing slowly.","If thoughts appear, gently return to the calm image."],"trick_title":"The “Heavy Eyes” Method","trick_steps":["When your eyes are closed in bed:","Keep your eyes closed.","Look slightly upward behind your eyelids.","Let your eyes become heavy.","This mimics the natural eye position that occurs right before sleep, helping the brain enter sleep","mode faster."],"close_secondary_message":"You reinforced reset the body clock today."}'::jsonb, '{}'::jsonb),
  ('sleep_disorder_reset', 2, 'Reducing Mental Stimulation', 'Phase 1: Reset the Clock', 'Reduce mental stimulation and racing thoughts at night while strengthening the sleep routine. By repeating the same steps from Day 1 and adding this new technique, the brain slowly begins to associate the routine with sleep.', '{"day_number":2,"day_title":"Reducing Mental Stimulation","day_goal":"Reduce mental stimulation and racing thoughts at night while strengthening the sleep routine. By repeating the same steps from Day 1 and adding this new technique, the brain slowly begins to associate the routine with sleep.","estimated_minutes":13,"lesson_highlight":"Stay consistent and let the routine do the work.","sunlight_instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","If sunlight is weak, increase exposure to 20–30 minutes."],"sunlight_why":"Morning sunlight resets the brain’s circadian clock, helping the body release melatonin naturally at night. Without this signal, the brain stays confused about when to sleep.","breathing_instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This reduces stress hormones and relaxes the nervous system.","movement_title":"Morning Movement (sleep Pressure Builder)","movement_exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]}],"caffeine_instructions":["Today follow this rule strictly:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain in the body 6–8 hours, which can silently disturb sleep."],"caffeine_why":"Small consistent actions reinforce stability and support restful sleep.","downshift_steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the voice instructions.","Let your body relax naturally.","Recommended audio length: 10–20 minutes."],"audio_day_path":"sleep_disorder_reset/day-02.mp3","audio_duration_seconds":624,"temperature_steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, your body temperature drops, which naturally triggers sleepiness.","This change signals the brain that nighttime has arrived."],"military_steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying on a quiet beach at sunset.","You can hear gentle waves and feel a cool breeze.","Keep breathing slowly while focusing on the scene."],"trick_title":"The Cognitive Shuffle","trick_steps":["If your mind keeps thinking when trying to sleep, use this technique.","In your mind, start naming random neutral objects.","This technique distracts the brain from problem-solving mode, which keeps people awake.","The mind becomes bored and begins transitioning into sleep mode."],"close_secondary_message":"You reinforced reducing mental stimulation today."}'::jsonb, '{}'::jsonb),
  ('sleep_disorder_reset', 3, 'Stabilizing Night Sleep', 'Phase 1: Reset the Clock', 'Reduce the effort and pressure around sleep, allowing the body to fall asleep more naturally.', '{"day_number":3,"day_title":"Stabilizing Night Sleep","day_goal":"Reduce the effort and pressure around sleep, allowing the body to fall asleep more naturally.","estimated_minutes":14,"lesson_highlight":"falling asleep faster","sunlight_instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","Try to walk slowly while getting sunlight. Movement strengthens the signal to your body clock."],"sunlight_why":"Morning sunlight resets the brain’s circadian rhythm, helping the body release melatonin naturally at night. Without this signal, sleep timing becomes irregular.","breathing_instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This lowers stress hormones and helps your body shift into a calm state.","movement_title":"Morning Movement (sleep Pressure Builder)","movement_exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]}],"caffeine_instructions":["Follow this rule strictly:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain in the body 6–8 hours and delay sleep onset."],"caffeine_why":"Small consistent actions reinforce stability and support restful sleep.","downshift_steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"audio_day_path":"sleep_disorder_reset/day-03.mp3","audio_duration_seconds":644,"temperature_steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, your body temperature drops slightly.","This drop triggers the brain to start producing melatonin, making you feel sleepy."],"military_steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet forest under a clear night sky.","The air is cool and peaceful.","Everything around you is still.","Focus on this scene while breathing slowly."],"trick_title":"The Reverse Blinking Technique","trick_steps":["This trick helps people who try too hard to fall asleep.","When lying in bed:","Close your eyes.","Open them gently for 1–2 seconds.","Close them again.","Repeat this 5–10 times slowly."],"close_secondary_message":"falling asleep faster"}'::jsonb, '{}'::jsonb),
  ('sleep_disorder_reset', 4, 'Reducing Night Awakenings', 'Phase 1: Reset the Clock', 'Improve sleep continuity and reduce middle-of-the-night awakenings.', '{"day_number":4,"day_title":"Reducing Night Awakenings","day_goal":"Improve sleep continuity and reduce middle-of-the-night awakenings.","estimated_minutes":14,"lesson_highlight":"fewer night wake-ups","sunlight_instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","Try to expose your eyes to full outdoor daylight, not through a window, because glass blocks part of","the light signal that helps regulate your body clock."],"sunlight_why":"Morning sunlight resets the brain’s circadian rhythm, helping your body release melatonin at night and improve sleep timing.","breathing_instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This lowers stress hormones and calms the nervous system.","movement_title":"Morning Movement (sleep Pressure Builder)","movement_exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]}],"caffeine_instructions":["Follow this rule strictly:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain active in the body 6–8 hours, disturbing sleep cycles."],"caffeine_why":"Small consistent actions reinforce stability and support restful sleep.","downshift_steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended audio length: 10–20 minutes."],"audio_day_path":"sleep_disorder_reset/day-04.mp3","audio_duration_seconds":647,"temperature_steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, the body experiences a natural drop in temperature, which signals the brain that it","is time to sleep."],"military_steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet field under a clear starry sky.","The night air is calm and peaceful.","Everything around you feels safe and quiet.","Focus on the scene while breathing slowly."],"trick_title":"The “15-Minute Reset Rule”","trick_steps":["If you wake up during the night and cannot fall asleep within about 15 minutes, do this:","Get out of bed quietly.","Go to a dimly lit room.","Sit or read something calm (no phone or bright screens).","Stay there for 5–10 minutes.","Return to bed when you feel sleepy."],"close_secondary_message":"fewer night wake-ups"}'::jsonb, '{}'::jsonb),
  ('sleep_disorder_reset', 5, 'Improving Deep Sleep Quality', 'Phase 1: Reset the Clock', 'Improve deep sleep quality and physical relaxation so the body can enter deeper restorative sleep cycles.', '{"day_number":5,"day_title":"Improving Deep Sleep Quality","day_goal":"Improve deep sleep quality and physical relaxation so the body can enter deeper restorative sleep cycles.","estimated_minutes":15,"lesson_highlight":"falling asleep faster","sunlight_instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","Combine sunlight exposure with a short walk to strengthen the signal to your body clock."],"sunlight_why":"Morning sunlight resets the brain’s circadian rhythm, helping the body release melatonin naturally at night.","breathing_instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This helps lower stress hormones and relax the nervous system.","movement_title":"Morning Movement (sleep Pressure Builder)","movement_exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]}],"caffeine_instructions":["Follow this rule strictly:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain active in the body 6–8 hours, affecting deep sleep cycles."],"caffeine_why":"Small consistent actions reinforce stability and support restful sleep.","downshift_steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"audio_day_path":"sleep_disorder_reset/day-05.mp3","audio_duration_seconds":658,"temperature_steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, your body temperature drops slightly.","This temperature drop signals the brain to prepare for sleep and melatonin release."],"military_steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet cabin during gentle rain.","You can hear the soft sound of rain on the roof.","Everything around you feels calm and safe.","Focus on the sound and scene while breathing slowly."],"trick_title":"The “Feet Warmth Trick”","trick_steps":["Cold feet can actually make it harder for the body to fall asleep.","Before going to bed:","wear light socks","or","place a warm blanket over your feet"],"close_secondary_message":"falling asleep faster"}'::jsonb, '{}'::jsonb),
  ('sleep_disorder_reset', 6, 'Quieting the Racing Mind', 'Phase 1: Reset the Clock', 'Reduce mental overload before bedtime, allowing the brain to relax and transition into sleep more easily.', '{"day_number":6,"day_title":"Quieting the Racing Mind","day_goal":"Reduce mental overload before bedtime, allowing the brain to relax and transition into sleep more easily.","estimated_minutes":15,"lesson_highlight":"quieter thoughts at night","sunlight_instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","Try walking slowly while getting sunlight to strengthen your circadian rhythm signal."],"sunlight_why":"Morning sunlight resets the brain’s internal clock, helping your body release melatonin naturally at night.","breathing_instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This reduces stress hormones and calms the nervous system.","movement_title":"Morning Movement (sleep Pressure Builder)","movement_exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]}],"caffeine_instructions":["Follow this rule strictly:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Caffeine can stay in the body 6–8 hours, delaying sleep onset."],"caffeine_why":"Small consistent actions reinforce stability and support restful sleep.","downshift_steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"audio_day_path":"sleep_disorder_reset/day-06.mp3","audio_duration_seconds":642,"temperature_steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, your body temperature naturally drops, which signals the brain to prepare for","sleep."],"military_steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet mountain valley at night.","The air is cool and peaceful.","Everything around you is still and calm.","Focus on the scene while breathing slowly."],"trick_title":"The “Brain Dump” Method","trick_steps":["Many people cannot sleep because the brain keeps thinking about tasks, worries, or tomorrow’s","problems.","About 30 minutes before bed, take a notebook and write down:","everything on your mind","tasks for tomorrow","worries or thoughts","Do not organize it. Just empty your mind onto paper."],"close_secondary_message":"quieter thoughts at night"}'::jsonb, '{}'::jsonb),
  ('sleep_disorder_reset', 7, 'Strengthening Natural Melatonin', 'Phase 1: Reset the Clock', 'Support the body’s natural melatonin cycle and strengthen the sleep routine developed during the first week.', '{"day_number":7,"day_title":"Strengthening Natural Melatonin","day_goal":"Support the body’s natural melatonin cycle and strengthen the sleep routine developed during the first week.","estimated_minutes":16,"lesson_highlight":"feeling sleepy earlier at night","sunlight_instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","If possible, expose your eyes to sunlight before looking at your phone. This gives a stronger signal to","your body clock."],"sunlight_why":"Morning sunlight resets the brain’s circadian rhythm, which controls the timing of melatonin release at night.","breathing_instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This lowers stress hormones and activates the relaxation response.","movement_title":"Morning Movement (sleep Pressure Builder)","movement_exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]}],"caffeine_instructions":["Follow this rule strictly:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain active in the body 6–8 hours, delaying sleep."],"caffeine_why":"Small consistent actions reinforce stability and support restful sleep.","downshift_steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the voice instructions.","Allow the body to relax naturally.","Recommended length: 10–20 minutes."],"audio_day_path":"sleep_disorder_reset/day-07.mp3","audio_duration_seconds":640,"temperature_steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, the body experiences a natural drop in temperature, which signals the brain that it","is time for sleep."],"military_steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet meadow under the stars.","The night air is cool and peaceful.","Everything around you is calm and still.","Focus on this scene while breathing slowly."],"trick_title":"The “Dim Light Rule”","trick_steps":["About 90 minutes before sleep, start reducing light exposure in your environment.","Turn off bright ceiling lights","Use warm or dim lighting","Reduce screen brightness","Avoid bright white lights"],"close_secondary_message":"feeling sleepy earlier at night"}'::jsonb, '{}'::jsonb),
  ('sleep_disorder_reset', 8, 'Strengthening Sleep Pressure', 'Phase 2: Build Sleep Pressure', 'Increase sleep pressure through more physical movement while strengthening relaxation techniques before bed. By this stage many people begin noticing: stronger sleepiness at night deeper sleep cycles more consistent sleep timing', '{"day_number":8,"day_title":"Strengthening Sleep Pressure","day_goal":"Increase sleep pressure through more physical movement while strengthening relaxation techniques before bed. By this stage many people begin noticing: stronger sleepiness at night deeper sleep cycles more consistent sleep timing","estimated_minutes":16,"lesson_highlight":"Stay consistent and let the routine do the work.","sunlight_instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","If possible, combine sunlight exposure with walking for 10 minutes."],"sunlight_why":"Morning sunlight resets the brain’s circadian rhythm, helping your body release melatonin naturally at night.","breathing_instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This helps lower stress hormones and prepares the body for the day.","movement_title":"Increased Morning Movement (sleep Pressure Builder)","movement_exercises":[{"name":"Starting Today, Increase Movement To 15–20 Minutes.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"10 Minutes Continuous Walking.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"15 Reps × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"10 Reps × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Arm Circles","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"20 Seconds × 3 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Forward Bends Stretch","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"10 Slow Repetitions","instructions":["Perform with steady breathing and controlled pacing."]}],"caffeine_instructions":["Follow this rule strictly:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain active in the body 6–8 hours and disturb sleep quality."],"caffeine_why":"Small consistent actions reinforce stability and support restful sleep.","downshift_steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"audio_day_path":"sleep_disorder_reset/day-08.mp3","audio_duration_seconds":640,"temperature_steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, your body temperature drops slightly, which signals the brain that it is time for","sleep."],"military_steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet forest clearing at night.","A gentle breeze moves through the trees.","The air is calm and peaceful.","Focus on the scene while breathing slowly."],"trick_title":"The “4-7-8 Sleep Breathing”","trick_steps":["This breathing technique helps slow the nervous system and induce sleep.","Inhale through your nose for 4 seconds","Hold your breath for 7 seconds","Slowly exhale through your mouth for 8 seconds","Repeat 4–6 cycles."],"close_secondary_message":"You reinforced strengthening sleep pressure today."}'::jsonb, '{"replace_slots":[{"slot_id":"morning_movement","hasEffortCheck":true}]}'::jsonb),
